const fs = require('fs');
const path = require('path');
const Joi = require('joi');
const logger = require('../../../common/logger');

let cachedProblems;

const MAX_LIMIT = 50;

/**
 * Normalize tags filter into a lowercase array.
 * @param {string|Array<string>} rawTags
 * @returns {Array<string>}
 */
function normalizeTags(rawTags) {
  if (!rawTags && rawTags !== '') {
    return [];
  }
  const list = Array.isArray(rawTags) ? rawTags : String(rawTags).split(',');
  return list
    .map((tag) => String(tag || '').trim().toLowerCase())
    .filter((tag) => tag);
}

/**
 * Check whether the problem contains at least one of the requested tags.
 * @param {Object} problem
 * @param {Array<string>} tags
 * @returns {boolean}
 */
function problemHasTags(problem, tags) {
  if (!tags || tags.length === 0) {
    return true;
  }
  if (!problem.tags || !Array.isArray(problem.tags)) {
    return false;
  }
  const problemTags = problem.tags.map((t) => t.toLowerCase());
  return tags.some((tag) => problemTags.includes(tag));
}

/**
 * Load problems from JSON file and cache them.
 * @returns {Array<Object>}
 */
function loadProblems() {
  if (cachedProblems) {
    return cachedProblems;
  }
  const filePath = path.join(__dirname, '..', '..', '..', 'data', 'problems.json');
  try {
    const content = fs.readFileSync(filePath, 'utf8');
    cachedProblems = JSON.parse(content);
    return cachedProblems;
  } catch (err) {
    logger.error('Failed to load problems.json:', err);
    cachedProblems = [];
    return cachedProblems;
  }
}

/**
 * List problems with optional filters.
 * @param {Object} query
 * @param {string} [query.tags]
 * @param {number} [query.limit]
 * @returns {Promise<Object>} - { total, result }
 */
function* listProblems(query) {
  const tags = normalizeTags(query.tags);
  let limit = parseInt(query.limit, 10);
  if (isNaN(limit) || limit <= 0) {
    limit = MAX_LIMIT;
  } else if (limit > MAX_LIMIT) {
    limit = MAX_LIMIT;
  }

  const problems = loadProblems();
  const filtered = problems.filter((p) => problemHasTags(p, tags));
  return {
    total: filtered.length,
    result: filtered.slice(0, limit),
  };
}

